sys_atf_test_step.step:
(function step(assert, $library) {
    // Test Scorecards CRUD operations
    // Create
    var gr = new GlideRecord('u_idp_scorecard');
    gr.initialize();
    gr.u_name = 'Test Scorecard ATF';
    gr.u_description = 'Test scorecard for ATF';
    var id = gr.insert();
    assert.isTrue(id, 'Scorecard should be created');

    // Read
    gr = new GlideRecord('u_idp_scorecard');
    gr.get(id);
    assert.equal(gr.u_name, 'Test Scorecard ATF', 'Scorecard name should match');

    // Update
    gr.u_description = 'Updated description';
    gr.update();

    // Delete
    gr.deleteRecord();

    // Verify deletion
    gr = new GlideRecord('u_idp_scorecard');
    gr.get(id);
    assert.isFalse(gr.isValid(), 'Scorecard should be deleted');
})(step, $library);
